public class Sum {
    public static void main(String[] args) {
        int total = 0;
        for (String s : args) {
            total += Integer.parseInt(s);
        }
        System.out.println("count=" + args.length);
        System.out.println("sum=" + total);
        System.out.printf("avg=%.1f%n", (double)total / args.length);
    }
}
